// src/components/TaskList.jsx
import React, { useState, useEffect } from "react";
import { db } from "../firebase/firebaseConfig";
import { ref, onValue } from "firebase/database";
import {
  completeTask,
  updateTask,
  deleteTask
} from "../firebase/firebaseService";

export default function TaskList({ onUpdate }) {
  const [tasks, setTasks] = useState([]);
  const [toast, setToast] = useState(null);

  useEffect(() => {
    const unsub = onValue(ref(db, "tasks"), (snap) => {
      const data = snap.val() || {};
      setTasks(Object.entries(data).map(([tid, d]) => ({ tid, ...d })));
    });
    return unsub;
  }, []);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleComplete = async (task) => {
    const res = await completeTask(
      task.tid,
      task.assignedTo,
      task.assignedName
    );

    if (res.success) {
      showToast(`+${res.pointsAwarded} pts`);
      onUpdate();
    }
  };

  const pending = tasks.filter((t) => t.status === "pending");
  const completed = tasks.filter((t) => t.status === "completed");

  return (
    <div className="card">
      <h2 className="card-title">📋 Tasks</h2>

      {toast && <div className={`toast ${toast.type}`}>{toast.msg}</div>}

      {/* PENDING */}
      <h3 className="section-label">Pending ({pending.length})</h3>

      {pending.length === 0 && (
        <p className="empty">No pending tasks 🎉</p>
      )}

      <ul className="task-list">
        {pending.map((task) => (
          <li key={task.tid} className="task-item pending">
            <div className="task-info">
              <span className="task-title">{task.title}</span>

              <span className="task-meta">
                {task.assignedName} · {task.points} pts
              </span>

              {task.dueDate && (
                <span className="task-meta">
                  📅 Due: {task.dueDate}
                </span>
              )}
            </div>

            <div className="task-actions">
              <button
                className="btn btn-complete"
                onClick={() => handleComplete(task)}
              >
                ✔ Complete
              </button>
              <button
                className="btn btn-delete"
                onClick={() => deleteTask(task.tid)}
              >
                🗑 Delete
              </button>
            </div>
          </li>
        ))}
      </ul>

      {/* COMPLETED */}
      <h3 className="section-label">Completed ({completed.length})</h3>

      <ul className="task-list">
        {completed.map((task) => (
          <li key={task.tid} className="task-item completed">
            <div className="task-info">
              <span className="task-title">{task.title}</span>

              <span className="task-meta">
                Done by {task.completedName}
              </span>
            </div>

            <span className="done-tag">✔ Done</span>
          </li>
        ))}
      </ul>
    </div>
  );
}
